import { useEffect, useRef, useState } from 'react';
import './Social.css';

const TWITTER_HANDLE = '_TheRead1';

function TwitterFeed({ handle }) {
  const ref = useRef(null);
  const [status, setStatus] = useState('loading');
  const loaded = useRef(false);

  useEffect(() => {
    // Only ever load once — prevent dev hot-reload from hammering Twitter
    if (loaded.current) return;
    loaded.current = true;

    const timeout = setTimeout(() => {
      setStatus(s => s === 'loading' ? 'failed' : s);
    }, 10000);

    const doRender = () => {
      if (!ref.current) return;
      window.twttr.widgets
        .createTimeline(
          { sourceType: 'profile', screenName: handle },
          ref.current,
          {
            tweetLimit: 6,
            chrome: 'noheader nofooter noborders transparent',
            theme: document.documentElement.getAttribute('data-theme') === 'dark' ? 'dark' : 'light',
            linkColor: '#6b8f71',
            lang: 'en',
          }
        )
        .then((el) => {
          clearTimeout(timeout);
          if (el) setStatus('ready');
          else setStatus('failed');
        })
        .catch(() => {
          clearTimeout(timeout);
          setStatus('failed');
        });
    };

    if (window.twttr?.widgets) {
      doRender();
    } else {
      const existing = document.getElementById('twitter-wjs');
      if (existing) existing.remove();

      const script = document.createElement('script');
      script.id = 'twitter-wjs';
      script.src = 'https://platform.twitter.com/widgets.js';
      script.async = true;
      script.charset = 'utf-8';
      script.onload = () => {
        window.twttr.ready(doRender);
      };
      script.onerror = () => {
        clearTimeout(timeout);
        setStatus('failed');
      };
      document.head.appendChild(script);
    }

    return () => clearTimeout(timeout);
  }, [handle]);

  return (
    <div className="twitter-feed-wrapper">
      {status === 'loading' && (
        <div className="twitter-feed-loading">
          {[1, 2, 3, 4, 5].map(i => (
            <div key={i} className="twitter-feed-skeleton glass">
              <div style={{ display: 'flex', gap: 10, marginBottom: 12 }}>
                <div className="skeleton" style={{ width: 40, height: 40, borderRadius: '50%', flexShrink: 0 }} />
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 6 }}>
                  <div className="skeleton" style={{ height: 12, width: '40%' }} />
                  <div className="skeleton" style={{ height: 11, width: '25%' }} />
                </div>
              </div>
              <div className="skeleton" style={{ height: 13, width: '95%', marginBottom: 6 }} />
              <div className="skeleton" style={{ height: 13, width: '75%' }} />
            </div>
          ))}
        </div>
      )}

      {status === 'failed' && (
        <div className="twitter-feed-fallback glass">
          <div className="twitter-feed-fallback__icon">
            <svg viewBox="0 0 24 24" width="28" height="28" fill="currentColor">
              <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-4.714-6.231-5.401 6.231H2.748l7.73-8.835L1.254 2.25H8.08l4.259 5.63zm-1.161 17.52h1.833L7.084 4.126H5.117z"/>
            </svg>
          </div>
          <p className="body" style={{ fontWeight: 500 }}>@{handle} on X</p>
          <p className="body-sm" style={{ color: 'var(--text-secondary)', marginTop: 6, maxWidth: 280 }}>
            Twitter is currently rate limiting this embed. Try refreshing once, or view the profile directly.
          </p>
          <div style={{ display: 'flex', gap: 10, marginTop: 20, flexWrap: 'wrap', justifyContent: 'center' }}>
            <button className="btn btn-ghost" onClick={() => { loaded.current = false; setStatus('loading'); }}>
              Try again
            </button>
            <a
              href={`https://twitter.com/${handle}`}
              target="_blank"
              rel="noopener noreferrer"
              className="btn btn-primary"
            >
              Open on X ↗
            </a>
          </div>
        </div>
      )}

      <div
        ref={ref}
        style={{ display: status === 'failed' ? 'none' : 'block' }}
      />
    </div>
  );
}

export default function Social() {
  return (
    <main className="social-page">
      <section className="social-page__hero section">
        <div className="container">
          <p className="caption fade-up">Social</p>
          <h1 className="heading-1 fade-up-1">Thoughts from the Field</h1>
          <p className="body-lg fade-up-2" style={{ color: 'var(--text-secondary)', maxWidth: 500, marginTop: 12 }}>
            Quick updates, research threads, and field observations from{' '}
            <a
              href={`https://twitter.com/${TWITTER_HANDLE}`}
              target="_blank"
              rel="noopener noreferrer"
              style={{ color: 'var(--accent)' }}
            >
              @{TWITTER_HANDLE}
            </a>.
          </p>
        </div>
      </section>

      <section className="section" style={{ paddingTop: 0 }}>
        <div className="container">
          <div className="social-page__grid fade-up-1">
            <div className="social-page__feed-card glass">
              <div className="social-page__feed-header">
                <div className="social-page__twitter-icon">
                  <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor">
                    <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-4.714-6.231-5.401 6.231H2.748l7.73-8.835L1.254 2.25H8.08l4.259 5.63zm-1.161 17.52h1.833L7.084 4.126H5.117z"/>
                  </svg>
                </div>
                <div>
                  <p className="body" style={{ fontWeight: 500 }}>@{TWITTER_HANDLE}</p>
                  <p className="body-sm" style={{ color: 'var(--text-tertiary)' }}>Latest posts</p>
                </div>
                <a
                  href={`https://twitter.com/${TWITTER_HANDLE}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="btn btn-ghost btn-sm"
                  style={{ marginLeft: 'auto' }}
                >
                  Follow
                </a>
              </div>
              <div className="social-page__feed-body">
                <TwitterFeed handle={TWITTER_HANDLE} />
              </div>
            </div>

            <div className="social-page__side">
              <div className="glass social-page__info-card">
                <p className="caption" style={{ marginBottom: 12 }}>About</p>
                <p className="body-sm" style={{ color: 'var(--text-secondary)', lineHeight: 1.7 }}>
                  Follow along for field updates, research threads, and thoughts on wood science, forestry, and sustainable construction.
                </p>
                <a
                  href={`https://twitter.com/${TWITTER_HANDLE}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="btn btn-primary"
                  style={{ marginTop: 20, width: '100%', justifyContent: 'center' }}
                >
                  Follow on X
                </a>
              </div>

              <div className="glass social-page__info-card">
                <p className="caption" style={{ marginBottom: 12 }}>Topics discussed</p>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                  {['Wood Science', 'Forestry', 'Construction', 'Industrialization', 'Sustainability', 'Research'].map(t => (
                    <span key={t} className="tag">{t}</span>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
    </main>
  );
}
